import { useEffect, memo, useState } from 'react';
import { useDispatch } from 'react-redux';
import { useNavigate } from 'react-router-dom';
import { setOnBoardingComplete } from '../../reduxStore/actions/flowActions';
import cls from './Login.module.scss';
import { LoginForm } from './LoginForm/LoginForm';
import { isMobile, isSafari } from 'react-device-detect';
import { resetApplication } from '../../services/auth.service';
import { getMasterData, getMobileData } from '../../services/master.service';
import { store } from '../../reduxStore/store';
import { APP_NAME, FLOWHERO, uncachedUrl } from '../../shared/utility';

const Login = memo(props => {
	const { title } = props;

	const navigate = useNavigate();
	//const dispatch = useDispatch();
	const { companyData, lastUpdates } = store.getState().flowReducer;
	const { authenticated } = store.getState().sessionReducer;
	const [company,] = useState(JSON.parse(localStorage.getItem('companyData')) ?? { 'logo': '' });
	document.title = `Login | ${APP_NAME}`;

	useEffect(() => {
		// if (authenticated){
		// 	navigate('/flowhero');
		// }else {
		// 	dispatch(setOnBoardingComplete(false));
		// 	resetApplication();
		// }
		resetApplication();
	}, []);

	return authenticated == false ? (
		<div className={cls.host} app-custom-media-show="hide">
			<div className={cls.firstContainer}>
				<p
					onClick={() => navigate('/flowhero')}
					style={{
						cursor: 'pointer',
						fontFamily: 'var(--app-text-main-font)',
						color: '#4A4A4A',
						textDecoration: 'underline',
						paddingLeft: '10px',
					}}
				>
					{isMobile ? `` : `Home`}
				</p>
				<div className={cls.headerTopBarContainer} style={{ fontSize: isMobile ? '12px' : '' }}>
					{company?.logo ?
						<img alt="lg" src={uncachedUrl(company?.logo)} className={isMobile ? cls.logoUrlImgMobile : cls.logoUrlImg} />
						:
						isMobile ? FLOWHERO('30px') :
							FLOWHERO('40px')}
					{!company?.logo && company?.display_name}

				</div>
				<div className={cls.firstContainerContent} style={{ marginTop: '40px', border: isMobile ? '0' : '', width: isMobile ? '70%' : '25%' }}>
					<LoginForm
						onLoginSuccess={data => {
							const { isSingleApp } = data;

							lastUpdates.componentsByModule = {};

							if (!(companyData?.status === 'trial_ended' || companyData?.status === 'inactive')) {
								if (isSingleApp === true && isMobile) {
									getMobileData();
									navigate('/mobile');
									return;
								} else {
									getMasterData();
									// getMobileData();
									// navigate('/mobile');
									// return;
								}
							} else if (companyData?.status === 'inactive') {
								getMasterData(true);
							} else {
								navigate('/login');
								return;
							}
							navigate('/');
						}}
						onResetPassword={() => navigate('/reset-password')}
					/>
				</div>
			</div>
		</div>
	) : (
		<div style={{ margin: 'auto', width: '100%', height: '500px', display: 'flex', alignContent: 'center', alignItems: 'center', justifyItems: 'center', justifyContent: 'center' }}>{FLOWHERO('30px')}</div>
	);
});

export default Login;
